const params = $('When Called').first().json.body.action.params;
const jobId = $('When Called').first().json.body.job_id;

const event = {
  summary: params.title,
  description: params.description || undefined,
  location: params.location || undefined,
  start: {
    dateTime: params.start_iso,
    timeZone: 'America/Argentina/Buenos_Aires'
  },
  end: {
    dateTime: params.end_iso,
    timeZone: 'America/Argentina/Buenos_Aires'
  },
};

// Add attendees if provided
if (params.attendees && params.attendees.length > 0) {
  event.attendees = params.attendees.map(email => ({ email }));
}

// Add Google Meet (default: true)
if (params.add_meet !== false) {
  event.conferenceData = {
    createRequest: {
      requestId: jobId,
      conferenceSolutionKey: { type: 'hangoutsMeet' }
    }
  };
}

return [{ json: event }];

const params = $('When Called').first().json.body.action.params;
const jobId = $('When Called').first().json.body.job_id;

const event = {};
if (params.title)       event.summary = params.title;
if (params.description) event.description = params.description;
if (params.start_iso)   event.start = { dateTime: params.start_iso, timeZone: 'America/Argentina/Buenos_Aires' };
if (params.end_iso)     event.end = { dateTime: params.end_iso, timeZone: 'America/Argentina/Buenos_Aires' };
if (params.attendees)   event.attendees = params.attendees.map(e => ({ email: e }));
if (params.add_meet !== false) {
  event.conferenceData = {
    createRequest: { requestId: `${jobId}-update`, conferenceSolutionKey: { type: 'hangoutsMeet' } }
  };
}

return [{ json: { eventId: params.event_id, body: event } }];

const event = $input.first().json;
const meetLink = event.conferenceData?.entryPoints?.find(e => e.entryPointType === 'video')?.uri || null;

// Format start date for human-readable response
const start = new Date(event.start?.dateTime || event.start?.date);
const startFmt = start.toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  weekday: 'long', day: 'numeric', month: 'long',
  hour: '2-digit', minute: '2-digit'
});

return [{ json: {
  success: true,
  event_id: event.id,
  title: event.summary,
  start_fmt: startFmt,
  attendees: (event.attendees || []).map(a => a.email),
  meet_link: meetLink,
  event_link: event.htmlLink,
}}];
